/**
 * @returns
 * 成功返回值为空字符串
 * 失败返回具体失败字符串
 */
function DownLoad500App() {
  try {
    var navigatorUserAgent = navigator.userAgent;
    var ua = navigatorUserAgent.toLowerCase() || '';
    var isAndroid = /android/.test(ua);
    var isWeixin = /micromessenger/.test(ua);
    var isIos = /iphone|ipad/.test(ua);
    var isSwan = /swan/.test(ua)
    // 百度小程序
    var isBaiduSwan = ua.indexOf('baiduboxapp') > -1 && isSwan
    var isEsApp = Boolean(
      window.EsApp && typeof window.EsApp.init === "function"
    );
    var evsDomain = "//ets.500.com";
    var DOWN_PC = window.location.protocol + "//www.500.com/wap/index.php";
    var IOS_DOWN_URL =
      window.location.protocol +
      "//itunes.apple.com/cn/app/ -cai-piao/id432486451";
    // 是否是移动端
    function isMobile() {
      var flag =
        /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(
          navigatorUserAgent
        );
      return flag;
    }
    // 获取安卓下载链接
    function getAndroidDownUrl(versionString) {
      return (
        window.location.protocol +
        "//soft.500.com/updatefiles/v" +
        versionString +
        "/500_lottery_client_for_Android_" +
        versionString +
        ".80002.apk"
      );
    }
    var DEFAULT_APPVERSION = getAndroidDownUrl("4.7.7");
    // PC端处理
    if (!isMobile()) {
      window.location.replace(DOWN_PC);
      return "isPc";
    }
    // 安卓微信处理
    if (isWeixin && isAndroid) {
      return "isAndroidWeixin";
    }
    // app 处理
    if (isEsApp) {
      return "isEsApp";
    }
    // 百度小程序处理
    if(isBaiduSwan) {
      return "isBaiduSwan";
    }
    // 成功处理
    if (isAndroid) {
      // 安卓
      var xhr = new XMLHttpRequest();
      xhr.onreadystatechange = function () {
        if (xhr.readyState == 4) {
          var resp = JSON.parse(xhr.responseText);
          if (resp.status == "100") {
            var version =
              resp.data && resp.data.android && resp.data.android.version_num;
            window.location.href = !version
              ? DEFAULT_APPVERSION
              : getAndroidDownUrl(version);
          } else {
            console.log(resp.message);
          }
        }
      };
      xhr.open(
        "post",
        evsDomain +
          "/thinfo/banner/latest_app_version?_t=" +
          new Date().getTime(),
        true
      ); // 打开链接
      xhr.setRequestHeader("Content-Type", "application/json; charset=utf-8"); // 设置请求头
      xhr.send("p=android"); // 设置需要携带到后端的字段，字符串形式
      return "";
    } else if (isIos) {
      //ios
      window.location.href = IOS_DOWN_URL;
      return "";
    }
    // 未知原因
    return "unknownError";
  } catch (error) {
    console.log(error);
    return "tryError";
  }
}
